package com.misw4203.vinilos.feature.home.domain.repository

import com.misw4203.vinilos.feature.home.domain.model.HomeItem
import kotlinx.coroutines.flow.Flow

interface HomeRepository {
    fun observeItems(): Flow<List<HomeItem>>
}

package com.misw4203.vinilos.feature.home.domain.repository
import com.misw4203.vinilos.feature.home.domain.model.HomeItem import kotlinx.coroutines.flow.Flow
interface HomeRepository { fun observeItems(): Flow<List<HomeItem>> fun observeItem(id: String): Flow<HomeItem?> }

package com.misw4203.vinilos.feature.home.domain.usecase

import com.misw4203.vinilos.feature.home.domain.model.HomeItem
import com.misw4203.vinilos.feature.home.domain.repository.HomeRepository
import kotlinx.coroutines.flow.Flow

class ObserveAlbumDetailUseCase(
    private val repository: HomeRepository,
) {
    operator fun invoke(id: String): Flow<HomeItem?> = repository.observeItem(id)
}

package com.misw4203.vinilos.feature.home.ui
import androidx.lifecycle.ViewModel import androidx.lifecycle.viewModelScope import com.misw4203.vinilos.feature.home.domain.usecase.ObserveAlbumDetailUseCase import kotlinx.coroutines.flow.SharingStarted import kotlinx.coroutines.flow.StateFlow import kotlinx.coroutines.flow.map import kotlinx.coroutines.flow.stateIn
class AlbumDetailViewModel( albumId: String, observeAlbumDetailUseCase: ObserveAlbumDetailUseCase, ) : ViewModel() {
val uiState: StateFlow<AlbumDetailUiState> = observeAlbumDetailUseCase(albumId) .map { album -> AlbumDetailUiState( isLoading = false, album = album, ) } .stateIn( scope = viewModelScope, started = SharingStarted.WhileSubscribed(5_000), initialValue = AlbumDetailUiState(), ) }
